namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new OrderService();
    }

    // --- CreateOrder: happy-path tests ---

    [TestMethod]
    public void CreateOrder_WithSingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(19.98m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsTotalCorrectly()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 10m, Quantity = 1 },
            new() { ProductName = "B", Price = 5m, Quantity = 3 }
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(25m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_AssignsNonEmptyIdAndUtcTimestamp()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1m, Quantity = 1 }
        };

        var before = DateTime.UtcNow;
        var order = _service.CreateOrder("cust-1", items);
        var after = DateTime.UtcNow;

        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    // --- CreateOrder: validation tests ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1m, Quantity = 1 }
        };

        Assert.ThrowsException<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // --- GetOrder tests ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsOrder()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 5m, Quantity = 1 }
        };
        var created = _service.CreateOrder("cust-1", items);

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer tests ---

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1m, Quantity = 1 }
        };

        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, result.Count);
        Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("nobody");

        Assert.AreEqual(0, result.Count);
    }
}

